<template>
  <div class="glass-effect rounded-2xl p-6">
    <div class="flex items-center justify-between mb-4">
      <div>
        <p class="text-sm text-gray-400">{{ card.title }}</p>
        <p class="text-3xl font-bold mt-2">{{ card.value }}</p>
      </div>
      <div class="w-12 h-12 rounded-xl bg-gradient-to-br" :class="card.color" />
    </div>
    
    <div class="flex items-center">
      <span class="text-sm" :class="changeColor">{{ card.change }}</span>
      <span class="text-gray-400 text-sm ml-2">本月</span>
    </div>
  </div>
</template>

<script setup lang="ts">
import { computed } from 'vue'

const props = defineProps<{
  card: {
    title: string
    value: string
    change: string
    color: string
    icon: string
  }
}>()

const changeColor = computed(() => {
  const change = props.card.change
  if (change.startsWith('+')) return 'text-green-400'
  return 'text-red-400'
})
</script>